# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import URLHandling

class UniversalLinkHandler: NSObject, URLHandler {
    func canHandle(url: URL) -> Bool {
        return url.host == "myapp.com" && url.path == "/reset-password"
    }
    
    func openURL(_ url: URL) -> Bool {
        guard let token = url.queryItems?.first(where: { $0.name == "token" })?.value else { return false }
        
        // Navigate to password reset screen with the parsed token
        UIApplication.shared.keyWindow?.rootViewController?.present(PasswordResetViewController(withToken: token), animated: true, completion: nil)
        
        return true
    }
}